def set_nested(d: dict, path: str, value: str) -> None:
    """Set a value in a nested dict using dot-notation path."""
    keys = path.split(".")
    for k in keys[:-1]:
        d = d.setdefault(k, {})
    d[keys[-1]] = value


def apply_translations(lang: str) -> int:
    path = BASE / lang / "common.json"
    with open(path, encoding="utf-8") as f:
        data = json.load(f)

    count = 0
    for dot_key, trans in TRANSLATIONS.items():
        if lang not in trans:
            continue
        # Only update if current value equals EN fallback
        # Navigate to current value
        keys = dot_key.split(".")
        cur = data
        found = True
        for k in keys:
            if isinstance(cur, dict) and k in cur:
                cur = cur[k]
            else:
                found = False
                break
        if found and isinstance(cur, str):
            set_nested(data, dot_key, trans[lang])
            count += 1
        elif not found:
            # Key doesn't exist yet, create it
            set_nested(data, dot_key, trans[lang])
            count += 1

    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
        f.write("\n")

    return count


if __name__ == "__main__":
    for lang in ["fr", "pl", "tr"]:
        n = apply_translations(lang)
        print(f"{lang}: updated {n} keys")
